1	interface Item {
2	  type: string;
3	}
4	
5	interface QuoteStep {
6	  op: "quote";
7	  items: Item[];
8	}
9	
10	type Step = QuoteStep;
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: Step[];
15	}
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	};
22	
23	const FIRST_INSURANCE_NUMERATOR = 11;
24	const FIRST_INSURANCE_DENOMINATOR = 10;
25	const PROCESSING_FEE = 5;
26	
27	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
28	  const results = scenario.steps.map((step) => {
29	    const base = step.items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
30	    const withFirstInsurance =
31	      (base * FIRST_INSURANCE_NUMERATOR) / FIRST_INSURANCE_DENOMINATOR;
32	    const premium = Math.ceil(withFirstInsurance + PROCESSING_FEE);
33	    return { premium };
34	  });
35	  return { results };
36	};
37

1	import { describe, it, expect } from "vitest";
